# Terraform: create a role-assignable group and configure PIM
# Note: azuread provider supports role-assignable groups

resource "azuread_group" "prod_ops" {
  display_name     = "prod-ops-team"
  security_enabled = true
  assignable_to_role = true   # makes group PIM-eligible; cannot be changed after creation
}

# Assign Azure RBAC role to the group
resource "azurerm_role_assignment" "prod_ops_contributor" {
  scope                = "/subscriptions/${var.subscription_id}/resourceGroups/prod-rg"
  role_definition_name = "Contributor"
  principal_id         = azuread_group.prod_ops.object_id
}

# Assign Entra role to the group
data "azuread_directory_role" "user_admin" {
  display_name = "User Administrator"
}
resource "azuread_directory_role_assignment" "prod_ops_user_admin" {
  role_id             = data.azuread_directory_role.user_admin.template_id
  principal_object_id = azuread_group.prod_ops.object_id
}

# PIM eligible membership assignments are not yet in the azuread provider;
# use azuread_group_member for permanent memberships or call MS Graph API
# via null_resource / local-exec for eligible assignments.
